		const button = shadowRoot.querySelector('button');
		assert.ok(button, 'button should be present in shadowRoot');

		// Check that styles are actually applied
		const computedStyle = window.getComputedStyle(button);
		assert.equal(computedStyle.width, '123px', 'button width should be 123px from styles');
		assert.equal(computedStyle.height, '123px', 'button height should be 123px from styles');
	}
});

